import{parse as twemojiParse}from"twemoji";import{DateTime}from"luxon";class NewsBoxUpdater{constructor(e=3e5){setInterval(this.getNews,e)}getNews(){if(!document.hasFocus())return;let e=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(t=>{t.json().then(t=>{t.data.forEach(e=>{let t=document.createElement("li"),a=document.createElement("a"),n=document.createElement("h6");a.href=`/news/${e.id}`,a.innerText=e.title,n.textContent=`(${DateTime.fromISO(e.created_at).toRelativeCalendar()})`,twemojiParse(a),t.appendChild(a),t.appendChild(n),e.push(t)}),e.replaceChildren([])})})}}class TagsBoxUpdater{constructor(){this.getTags()}getTags(){let e=document.getElementById("tag-container");fetch("/api/tags?sort=post_count&order=desc").then(t=>{t.json().then(t=>{t.data.forEach(t=>{if(t.post_count>0&&"banned"!=t.type){var a=document.createElement("li"),n=document.createElement("a"),o=document.createElement("div");n.href=`/posts/?tags=${t.name}`,n.innerText=t.humanized,o.innerText=t.post_count,n.classList.add("tag-list-item"),a.classList.add(t.type),a.appendChild(n),a.appendChild(o),a.onclick=()=>{location.href=`/posts/?tags=${t.name}`},e.appendChild(a)}})})})}}export{NewsBoxUpdater,TagsBoxUpdater};